import 'package:http/http.dart' as http;
import 'dart:convert';
import '../models/models.dart';

class ApiClient {
  static const String baseUrl = 'https://api.nirdist.com/api';  // Replace with your actual backend URL
  // static const String baseUrl = 'http://localhost:8080/api';
  // For Android device/emulator, use: 'http://10.0.2.2:8080/api'
  static String? _token;

  static void setToken(String token) {
    _token = token;
  }

  static Map<String, String> _getHeaders() {
    final headers = {'Content-Type': 'application/json'};
    if (_token != null) {
      headers['Authorization'] = 'Bearer $_token';
    }
    return headers;
  }

  // Auth
  static Future<Map<String, dynamic>> register({
    required String vName,
    required String vUsername,
    required String email,
    required String password,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$baseUrl/auth/register'),
        headers: _getHeaders(),
        body: jsonEncode({
          'v_name': vName,
          'v_username': vUsername,
          'email': email,
          'password': password,
        }),
      );

      if (response.statusCode == 201) {
        final data = jsonDecode(response.body);
        _token = data['token'];
        return data;
      } else {
        if (response.body.isEmpty) {
          throw Exception('Registration failed: empty response from server');
        }
        try {
          final errorData = jsonDecode(response.body);
          throw Exception(errorData['message'] ?? 'Registration failed');
        } catch (e) {
          throw Exception('Registration failed: ${response.statusCode}');
        }
      }
    } catch (e) {
      rethrow;
    }
  }

